def minAddToMakeValid(s: str) -> int:
    stack = []
    count = 0
    for char in s:
        if char == '(':
            stack.append(char)
            count += 1
        elif char == ')':
            if len(stack) == 0:
                return count
            stack.pop()
    return count + len(stack)

